SELECT AVG(f.students) AS average_students
FROM financial_data f
WHERE f.year = 1999;

SELECT (
  SELECT COUNT(*) 
  FROM data_exports 
  WHERE user_id=1
) AS total_exports, (
  SELECT COUNT(DISTINCT role_id) 
  FROM user_roles 
  WHERE user_id=1
) AS total_roles;

SELECT state_name
FROM states
WHERE state_population > (
    SELECT SUM(students)
    FROM financial_data
);

SELECT COUNT(DISTINCT user_id) AS total_users
FROM access_logs
WHERE strftime('%Y', access_date) = '2023';
